#include <stdlib.h>
#include <stdio.h>
#include <stdbool.h>
#include <unistd.h>

#define MAX_HANDLES 1024

typedef struct {
    int* handles;
    size_t count;
    size_t capacity;
    bool is_cleaned;
} file_handle_list_t;

file_handle_list_t* handle_list_create(void) {
    file_handle_list_t* list = malloc(sizeof(file_handle_list_t));
    if (!list) return NULL;
    
    list->handles = malloc(MAX_HANDLES * sizeof(int));
    if (!list->handles) {
        free(list);
        return NULL;
    }
    
    list->count = 0;
    list->capacity = MAX_HANDLES;
    list->is_cleaned = false;
    
    return list;
}

bool handle_list_add(file_handle_list_t* list, int handle) {
    if (!list || list->is_cleaned) return false;
    if (list->count >= list->capacity) return false;
    
    list->handles[list->count] = handle;
    list->count++;
    
    return true;
}

bool handle_list_remove(file_handle_list_t* list, int handle) {
    if (!list || list->is_cleaned) return false;
    
    for (size_t i = 0; i < list->count; i++) {
        if (list->handles[i] == handle) {
            // Shift elements to fill the gap
            for (size_t j = i; j < list->count - 1; j++) {
                list->handles[j] = list->handles[j + 1];
            }
            list->count--;
            return true;
        }
    }
    
    return false;
}

void handle_list_cleanup(file_handle_list_t** list_ptr) {
    if (!list_ptr || !*list_ptr || (*list_ptr)->is_cleaned) {
        return;
    }
    
    file_handle_list_t* list = *list_ptr;
    
    // Close all file descriptors
    for (size_t i = 0; i < list->count; i++) {
        close(list->handles[i]);
    }
    
    // Free memory
    free(list->handles);
    free(list);
    
    *list_ptr = NULL;
    list = NULL;
}